NXOpen::Expression* FindExpressionIfExists(NXOpen::Part* part, const char* expressionName)
{
	if (part == NULL || expressionName == NULL || expressionName[0] == '\0')
	{
		return NULL;
	}

	try
	{
		return dynamic_cast<NXOpen::Expression*>(part->Expressions()->FindObject(expressionName));
	}
	catch (NXOpen::NXException&)
	{
		return NULL;
	}
}

void SetOrCreateIntegerExpression(NXOpen::Part* part, const char* expressionName, const char* rightHandSide)
{
	if (part == NULL || expressionName == NULL || rightHandSide == NULL)
	{
		return;
	}

	NXOpen::Expression* expression1 = FindExpressionIfExists(part, expressionName);
	if (expression1 != NULL)
	{
		expression1->SetRightHandSide(rightHandSide);
		return;
	}

	char expressionFormula[512];
	sprintf(expressionFormula, "%s=%s", expressionName, rightHandSide);
	NXOpen::Unit* nullNXOpen_Unit(NULL);
	part->Expressions()->CreateExpressionWithUnit("Integer", expressionFormula, nullNXOpen_Unit);
}

void AddBodyIfMissing(std::vector<Body*>& bodies, Body* body1)
{
	if (body1 == NULL)
	{
		return;
	}
	if (std::find(bodies.begin(), bodies.end(), body1) == bodies.end())
	{
		bodies.push_back(body1);
	}
}

void CollectBodiesFromPart(NXOpen::Part* part, std::vector<Body*>& bodies)
{
	if (part == NULL)
	{
		return;
	}

	NXOpen::BodyCollection* bodyCollection = part->Bodies();
	for (NXOpen::BodyCollection::iterator it = bodyCollection->begin(); it != bodyCollection->end(); ++it)
	{
		AddBodyIfMissing(bodies, *it);
	}
}

void CollectBodiesFromComponent(NXOpen::Assemblies::Component* component, std::vector<Body*>& bodies)
{
	if (component == NULL)
	{
		return;
	}

	NXOpen::Part* prototypePart = dynamic_cast<NXOpen::Part*>(component->Prototype());
	if (prototypePart != NULL)
	{
		NXOpen::BodyCollection* bodyCollection = prototypePart->Bodies();
		for (NXOpen::BodyCollection::iterator it = bodyCollection->begin(); it != bodyCollection->end(); ++it)
		{
			NXOpen::NXObject* occurrenceObject = component->FindOccurrence(*it);
			Body* occurrenceBody = dynamic_cast<Body*>(occurrenceObject);
			AddBodyIfMissing(bodies, occurrenceBody != NULL ? occurrenceBody : *it);
		}
	}

	std::vector<NXOpen::Assemblies::Component*> children = component->GetChildren();
	for (size_t i = 0; i < children.size(); ++i)
	{
		CollectBodiesFromComponent(children[i], bodies);
	}
}

void CollectBatchBodies(NXOpen::Part* part, std::vector<Body*>& bodies)
{
	CollectBodiesFromPart(part, bodies);
	if (part == NULL || part->ComponentAssembly() == NULL)
	{
		return;
	}

	NXOpen::Assemblies::Component* rootComponent = part->ComponentAssembly()->RootComponent();
	if (rootComponent == NULL)
	{
		return;
	}

	std::vector<NXOpen::Assemblies::Component*> children = rootComponent->GetChildren();
	for (size_t i = 0; i < children.size(); ++i)
	{
		CollectBodiesFromComponent(children[i], bodies);
	}
}

bool ExpressionNameBelongsToBody(NXOpen::Part* part, NXOpen::Body* body1, const char* expressionName)
{
	if (part == NULL || body1 == NULL || expressionName == NULL || expressionName[0] == '\0')
	{
		return false;
	}

	NXOpen::Expression* namedExpression = FindExpressionIfExists(part, expressionName);
	if (namedExpression == NULL)
	{
		return false;
	}

	try
	{
		NXOpen::Expression* bodyExpression =
			part->Expressions()->GetAttributeExpression(body1, "sulian", NXOpen::NXObject::AttributeTypeInteger, -1);
		return bodyExpression != NULL && bodyExpression->Tag() == namedExpression->Tag();
	}
	catch (NXOpen::NXException&)
	{
		return false;
	}
}

bool BodyIdIsAvailable(NXOpen::Part* part, NXOpen::Body* body1, int bodyId)
{
	if (part == NULL || body1 == NULL)
	{
		return true;
	}

	char suLian[256];
	char zSuLian[256];
	sprintf(suLian, "SuLian_%d", bodyId);
	sprintf(zSuLian, "ZSuLian_%d", bodyId);

	NXOpen::Expression* suLianExpression = FindExpressionIfExists(part, suLian);
	if (suLianExpression != NULL && !ExpressionNameBelongsToBody(part, body1, suLian))
	{
		return false;
	}

	NXOpen::Expression* zSuLianExpression = FindExpressionIfExists(part, zSuLian);
	if (zSuLianExpression != NULL && suLianExpression == NULL)
	{
		return false;
	}

	return true;
}

int GenerateAvailableBodyId(NXOpen::Part* part, NXOpen::Body* body1)
{
	static bool randomSeeded = false;
	if (!randomSeeded)
	{
		srand(static_cast<unsigned int>(time(0)));
		randomSeeded = true;
	}

	for (int tryIndex = 0; tryIndex < 9001; ++tryIndex)
	{
		const int bodyId = (rand() % 9001) + 999;
		if (BodyIdIsAvailable(part, body1, bodyId))
		{
			return bodyId;
		}
	}

	for (int bodyId = 999; bodyId <= 9999; ++bodyId)
	{
		if (BodyIdIsAvailable(part, body1, bodyId))
		{
			return bodyId;
		}
	}

	return static_cast<int>(body1->Tag());
}

int GetOrCreateBodyId(NXOpen::Part* part, NXOpen::Body* body1)
{
	if (body1->HasUserAttribute("BodyID", NXOpen::NXObject::AttributeType::AttributeTypeInteger, -1))
	{
		const int bodyId = body1->GetIntegerAttribute("BodyID");
		if (BodyIdIsAvailable(part, body1, bodyId))
		{
			return bodyId;
		}
	}

	const int bodyId = GenerateAvailableBodyId(part, body1);
	body1->SetUserAttribute("BodyID", -1, bodyId, Update::Option::OptionNow);
	return bodyId;
}

void CreateSulianExpressions(NXOpen::Part* part, NXOpen::Body* body1, int bodyId, const char* quantityExpressionName)
{
	if (part == NULL || body1 == NULL || quantityExpressionName == NULL)
	{
		return;
	}

	char suLian[256];
	char zSuLian[256];
	char zSuLianRightHandSide[256];
	sprintf(suLian, "SuLian_%d", bodyId);
	sprintf(zSuLian, "ZSuLian_%d", bodyId);
	sprintf(zSuLianRightHandSide, "%s*%s", quantityExpressionName, suLian);

	NXOpen::Expression* expSuLian =
		part->Expressions()->GetAttributeExpression(body1, "sulian", NXOpen::NXObject::AttributeTypeInteger, -1);
	try
	{
		expSuLian->SetName(suLian);
	}
	catch (NXOpen::NXException&)
	{
	}

	SetOrCreateIntegerExpression(part, zSuLian, zSuLianRightHandSide);
}
